Create the extension point registry as a Zustand store with typed slot contributions, a convenience query hook, and unit tests.

## Files to Create

### `apps/client/src/layers/shared/model/extension-registry.ts`

This file contains all registry types, the Zustand store, and the `useSlotContributions` hook.

```typescript
import { useMemo } from 'react';
import { create } from 'zustand';
import { devtools } from 'zustand/middleware';
import type { LucideIcon } from 'lucide-react';
import type { ComponentType } from 'react';

// --- Slot ID Constants ---

export const SLOT_IDS = {
  SIDEBAR_FOOTER: 'sidebar.footer',
  SIDEBAR_TABS: 'sidebar.tabs',
  DASHBOARD_SECTIONS: 'dashboard.sections',
  HEADER_ACTIONS: 'header.actions',
  COMMAND_PALETTE_ITEMS: 'command-palette.items',
  DIALOG: 'dialog',
  SETTINGS_TABS: 'settings.tabs',
  SESSION_CANVAS: 'session.canvas',
} as const;

export type SlotId = (typeof SLOT_IDS)[keyof typeof SLOT_IDS];

// --- Contribution Base ---

/** Base interface for all contributions. */
export interface BaseContribution {
  /** Unique identifier within the slot. */
  id: string;
  /** Sort priority. Lower = higher priority. Default: 50. */
  priority?: number;
}

// --- Per-Slot Contribution Interfaces ---

export interface SidebarFooterContribution extends BaseContribution {
  icon: LucideIcon;
  label: string;
  onClick: () => void;
  /** Only show when `import.meta.env.DEV` is true. */
  showInDevOnly?: boolean;
}

export interface SidebarTabContribution extends BaseContribution {
  icon: LucideIcon;
  label: string;
  component: ComponentType;
  /** Return false to hide this tab. Evaluated reactively. */
  visibleWhen?: () => boolean;
  /** Keyboard shortcut label (e.g., "⌘1"). */
  shortcut?: string;
}

export interface DashboardSectionContribution extends BaseContribution {
  component: ComponentType;
  title?: string;
  /** Return false to hide this section. Evaluated reactively. */
  visibleWhen?: () => boolean;
}

export interface HeaderActionContribution extends BaseContribution {
  icon: LucideIcon;
  label: string;
  onClick: () => void;
  variant?: 'default' | 'ghost' | 'outline';
}

export interface CommandPaletteContribution extends BaseContribution {
  label: string;
  /** Lucide icon name (string, not component). */
  icon: string;
  /** Action identifier dispatched via `usePaletteActions`. */
  action: string;
  shortcut?: string;
  category: 'feature' | 'quick-action';
}

export interface DialogContribution extends BaseContribution {
  /** Dialog component accepting `open` and `onOpenChange` props. */
  component: ComponentType<{ open: boolean; onOpenChange: (open: boolean) => void }>;
  /** Key in `useAppStore()` that controls open state (e.g., 'settingsOpen'). */
  openStateKey: string;
}

export interface SettingsTabContribution extends BaseContribution {
  label: string;
  icon: LucideIcon;
  component: ComponentType;
}

export interface SessionCanvasContribution extends BaseContribution {
  component: ComponentType;
  /** MIME-like content type this renderer handles. */
  contentType: string;
}

// --- Slot Contribution Map ---

/**
 * Maps slot IDs to their contribution types.
 * Declared as an interface (not type) to support `declare module` augmentation in Phase 3.
 */
export interface SlotContributionMap {
  'sidebar.footer': SidebarFooterContribution;
  'sidebar.tabs': SidebarTabContribution;
  'dashboard.sections': DashboardSectionContribution;
  'header.actions': HeaderActionContribution;
  'command-palette.items': CommandPaletteContribution;
  dialog: DialogContribution;
  'settings.tabs': SettingsTabContribution;
  'session.canvas': SessionCanvasContribution;
}

// --- Store ---

interface ExtensionRegistryState {
  /** Internal storage: slot ID -> array of contributions. */
  slots: { [K in SlotId]: SlotContributionMap[K][] };
  /** Register a contribution to a slot. Returns an unsubscribe function. */
  register: <K extends SlotId>(slotId: K, contribution: SlotContributionMap[K]) => () => void;
  /** Get raw (unsorted) contributions for a slot. */
  getContributions: <K extends SlotId>(slotId: K) => SlotContributionMap[K][];
}

/** Initial state factory -- every slot starts empty. */
export function createInitialSlots(): ExtensionRegistryState['slots'] {
  return Object.values(SLOT_IDS).reduce(
    (acc, id) => ({ ...acc, [id]: [] }),
    {} as ExtensionRegistryState['slots']
  );
}

export const useExtensionRegistry = create<ExtensionRegistryState>()(
  devtools(
    (set, get) => ({
      slots: createInitialSlots(),

      register: (slotId, contribution) => {
        const withDefaults = { priority: 50, ...contribution };

        set(
          (state) => ({
            slots: {
              ...state.slots,
              [slotId]: [...state.slots[slotId], withDefaults],
            },
          }),
          undefined,
          `register/${slotId}/${contribution.id}`
        );

        // Return unsubscribe function
        return () => {
          set(
            (state) => ({
              slots: {
                ...state.slots,
                [slotId]: state.slots[slotId].filter((c) => c.id !== contribution.id),
              },
            }),
            undefined,
            `unregister/${slotId}/${contribution.id}`
          );
        };
      },

      getContributions: (slotId) => get().slots[slotId],
    }),
    { name: 'extension-registry' }
  )
);

// --- Convenience Hook ---

/**
 * Subscribe to a slot and return its contributions sorted by priority.
 * Lower priority number = appears first. Stable sort preserves insertion order for ties.
 */
export function useSlotContributions<K extends SlotId>(slotId: K): SlotContributionMap[K][] {
  const contributions = useExtensionRegistry((state) => state.slots[slotId]);

  return useMemo(
    () => [...contributions].sort((a, b) => (a.priority ?? 50) - (b.priority ?? 50)),
    [contributions]
  );
}
```

### `apps/client/src/layers/shared/model/__tests__/extension-registry.test.ts`

```typescript
import { describe, it, expect, beforeEach } from 'vitest';
import {
  useExtensionRegistry,
  createInitialSlots,
  SLOT_IDS,
} from '../extension-registry';
import type {
  SidebarFooterContribution,
  DialogContribution,
  CommandPaletteContribution,
} from '../extension-registry';

// Test contributions via getState() without React rendering.
// Reset between tests per Zustand testing guide.

const makeSidebarFooter = (
  overrides: Partial<SidebarFooterContribution> = {}
): SidebarFooterContribution => ({
  id: 'test-button',
  icon: (() => null) as unknown as SidebarFooterContribution['icon'],
  label: 'Test',
  onClick: () => {},
  ...overrides,
});

describe('extension-registry', () => {
  beforeEach(() => {
    useExtensionRegistry.setState({ slots: createInitialSlots() }, true);
  });

  it('registers and retrieves a contribution', () => {
    const { register, getContributions } = useExtensionRegistry.getState();
    const button = makeSidebarFooter({ id: 'btn-1' });

    register('sidebar.footer', button);

    const items = getContributions('sidebar.footer');
    expect(items).toHaveLength(1);
    expect(items[0].id).toBe('btn-1');
  });

  it('unregister removes the contribution', () => {
    const { register, getContributions } = useExtensionRegistry.getState();
    const unsubscribe = register('sidebar.footer', makeSidebarFooter({ id: 'btn-remove' }));

    expect(getContributions('sidebar.footer')).toHaveLength(1);

    unsubscribe();

    expect(useExtensionRegistry.getState().getContributions('sidebar.footer')).toHaveLength(0);
  });

  it('sorts contributions by priority (lower = first)', () => {
    const { register } = useExtensionRegistry.getState();
    register('sidebar.footer', makeSidebarFooter({ id: 'p3', priority: 3 }));
    register('sidebar.footer', makeSidebarFooter({ id: 'p1', priority: 1 }));
    register('sidebar.footer', makeSidebarFooter({ id: 'p2', priority: 2 }));

    // useSlotContributions is a React hook, so test sort logic directly
    const raw = useExtensionRegistry.getState().getContributions('sidebar.footer');
    const sorted = [...raw].sort((a, b) => (a.priority ?? 50) - (b.priority ?? 50));
    expect(sorted.map((c) => c.id)).toEqual(['p1', 'p2', 'p3']);
  });

  it('does not affect other slots when registering', () => {
    const { register, getContributions } = useExtensionRegistry.getState();
    register('sidebar.footer', makeSidebarFooter({ id: 'btn-isolated' }));

    expect(getContributions('dialog')).toHaveLength(0);
    expect(getContributions('sidebar.tabs')).toHaveLength(0);
  });

  it('returns empty array for a slot with no registrations', () => {
    const { getContributions } = useExtensionRegistry.getState();
    expect(getContributions('session.canvas')).toEqual([]);
  });

  it('applies default priority of 50 when not specified', () => {
    const { register, getContributions } = useExtensionRegistry.getState();
    register('sidebar.footer', makeSidebarFooter({ id: 'no-priority' }));

    const items = getContributions('sidebar.footer');
    expect(items[0].priority).toBe(50);
  });

  it('preserves insertion order for contributions with equal priority (stable sort)', () => {
    const { register } = useExtensionRegistry.getState();
    register('sidebar.footer', makeSidebarFooter({ id: 'first', priority: 10 }));
    register('sidebar.footer', makeSidebarFooter({ id: 'second', priority: 10 }));
    register('sidebar.footer', makeSidebarFooter({ id: 'third', priority: 10 }));

    const raw = useExtensionRegistry.getState().getContributions('sidebar.footer');
    const sorted = [...raw].sort((a, b) => (a.priority ?? 50) - (b.priority ?? 50));
    expect(sorted.map((c) => c.id)).toEqual(['first', 'second', 'third']);
  });
});
```

